#include <bits/stdc++.h>
using namespace std;
int n,a,q,m;
map<int,int> p;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a);
        p[a]=i;
    }
    scanf("%d",&q);
    while(q--){
        scanf("%d",&m);
        printf("%d\n",p[m]);
    }
    return 0;
}
